import re

# Check remaining "No appendix" papers
for vid in ['2602.21716', '2602.21956', '2602.22142', '2602.23393']:
    with open(f'/tmp_workspace/papers/{vid}.html', 'r') as f:
        html = f.read()

    refs_match = re.search(r'<h[1-6][^>]*>\s*References?\s*</h', html, re.IGNORECASE)
    if refs_match:
        after_refs = html[refs_match.end():]
        next_h = re.search(r'<h([1-6])[^>]*>(.*?)</h\1>', after_refs, re.DOTALL)
        if next_h:
            heading_text = re.sub(r'<[^>]+>', ' ', next_h.group(1) + ": " + next_h.group(2)).strip()
            print(f"{vid}: Next heading after References: '{heading_text[:60]}'")
        else:
            print(f"{vid}: No heading after References")
    else:
        print(f"{vid}: No References heading found")
        # Look for any appendix patterns
        if 'appendix' in html.lower():
            print(f"  But 'appendix' found in HTML")
        if 'supplementary' in html.lower():
            print(f"  But 'supplementary' found in HTML")
PYEOF
